tokens_css:
/* Amaris Consulting — Brand Tokens
   Generated by brand-artifact-builder · 2026-05-09
   Refreshed 2026-05-19 — added brand-defined semantic colors from live amaris.com :root vars
   Source: charter.json (Tier 4 CSS vars, high confidence)
*/

:root {
  /* Core palette */
  --color-primary:         #272674;   /* Navy indigo — primary brand blue */
  --color-secondary:       #f5e2da;   /* Warm peach */
  --color-accent:          #4182ff;   /* Digital blue */
  --color-text:            #494951;   /* Body text charcoal */
  --color-text-light:      #6c757d;   /* Muted gray (amaris --gray) */
  --color-background:      #ffffff;
  --color-background-alt:  #f8f9fa;   /* Light grey surface */
  --color-surface:         #f8f9fa;   /* Card/section surface (amaris --light) */
  --color-text-on-dark:    #ffffff;
  --color-text-on-accent:  #ffffff;

  /* Semantic state colors — brand-defined (not Bootstrap defaults) */
  --color-success:         #7ddeb8;   /* amaris --success (life-sciences green) */
  --color-warning:         #ffdd77;   /* amaris --warning (telecom yellow) */
  --color-error:           #ff4d4d;   /* amaris --danger */

  /* Sector accent colours */
  --color-life-sciences:   #7ddeb8;   /* Mint green */
  --color-engineering:     #b880ff;   /* Purple */
  --color-telecom:         #ffdd77;   /* Yellow */
  --color-digital:         #4182ff;   /* Blue (same as accent) */

  /* Gradient */
  --gradient-midnight:     linear-gradient(135deg, #020381 0%, #2874fc 100%);
  --gradient-dark:         linear-gradient(135deg, #272674 0%, #000000 100%);
  --gradient-accent:       linear-gradient(135deg, #4182ff 0%, #272674 100%);

  /* Typography
     Primary brand font: Century Gothic (system font on macOS/Windows, no embed needed).
     Century Gothic ships with two weights only (Regular 400, Bold 700) — do not
     rely on intermediate weights. */
  --font-heading:          'Century Gothic', 'CenturyGothic', 'Avenir Next', 'Futura', 'Apple SD Gothic Neo', sans-serif;
  --font-body:             'Century Gothic', 'CenturyGothic', 'Avenir Next', 'Futura', 'Apple SD Gothic Neo', sans-serif;
  --font-accent:           'Quicksand', sans-serif;
  --font-mono:             'SFMono-Regular', 'Menlo', 'Monaco', 'Consolas', monospace;

  --font-weight-regular:   400;
  --font-weight-medium:    700;  /* Century Gothic has no true medium — alias to bold */
  --font-weight-semibold:  700;  /* Same — alias to bold */
  --font-weight-bold:      700;

  --font-size-base:        18px;
  --font-size-h1:          48px;
  --font-size-h2:          36px;
  --font-size-small:       13px;
  --font-size-medium:      20px;
  --font-size-large:       36px;
  --font-size-xl:          42px;

  /* Layout */
  --content-width:         985px;
  --wide-width:            1200px;

  /* Spacing scale (from theme) */
  --spacing-xs:            0.44rem;
  --spacing-sm:            0.67rem;
  --spacing-md:            1rem;
  --spacing-lg:            1.5rem;
  --spacing-xl:            2.25rem;
  --spacing-2xl:           3.38rem;
  --spacing-3xl:           5.06rem;

  /* Orbit / stepping-stone motif
     Recovered from the official PPTX master (PLAN_amaris-motif-system). Generic
     --motif-* primitives + brand-specific --orbit-* detail tokens; shared
     renderers key only off --motif-* / motifProminence, never --orbit-*. */
  --motif-line-weight:     0.9px;                    /* hairline arc stroke */
  --motif-arc-color-dark:  rgba(255, 255, 255, 0.30);
  --motif-arc-color-light: rgba(39, 38, 116, 0.14);
  --motif-ghost-opacity:   0.08;
  --orbit-dot-1:           #4182ff;                  /* blue   */
  --orbit-dot-2:           #7ddeb8;                  /* mint   */
  --orbit-dot-3:           #ffdd77;                  /* yellow */
  --orbit-dot-4:           #b880ff;                  /* purple */
  --orbit-dot-glow:        0 0 24px rgba(65, 130, 255, 0.45);
  --gradient-canvas-light: linear-gradient(180deg, #ffffff 0%, #f5e2da 100%);
  --accent-warm:           #FBAE40;
  --accent-coral:          #F26B43;

  /* Motion (PLAN_motion-capability — reference instance). Cross-surface
     --motion-* family read by the format-motion primitives with neutral
     var(--token, default) fallbacks. Amaris is a subtle-tier brand: durations
     tightened below the neutral defaults, short travel, no cinematic timing.
     prefers-reduced-motion always collapses these to static (handled by the
     primitives, not the tokens). Intensity/intent live in
     expression.visual_grammar.motion.spec. */
  --motion-duration-reveal:     360ms;   /* entrance / reveal (neutral 420) */
  --motion-duration-emphasize:  500ms;   /* emphasis pulse  (neutral 600)   */
  --motion-duration-transition: 280ms;   /* state-to-state  (neutral 320)   */
  --motion-duration-explain:   1100ms;   /* orbit-arc line-draw (neutral 1200) */
  --motion-ease:               cubic-bezier(.22, .61, .36, 1);  /* systematic ease-out */
  --motion-stagger:             60ms;    /* tight per-child step (neutral 70) */
  --motion-distance:            12px;    /* small entrance travel (neutral 16) */
}

/* --- visual grammar tokens (brand-visual-grammar; 2026-07-01) ---
   backgrounds + iconography + elevation. gradients / content-width / orbit
   already tokenized above. Applied downstream, reference-not-bind. --- */
:root {
  --canvas-navy:  #272674;
  --canvas-paper: #FFFFFF;
  --canvas-blush: #F5E2DA;
  --icon-stroke:  1.5px;
  --elev-border:  1px solid rgba(39,38,116,0.14);
  --card-index-border: 3px;
}

/* --- image treatment system (Component T; ORG-PLAN-045) ---
   Definition of record: charter.expression.treatments. Applied downstream
   (format-MCP render + website .img-treatment), never pre-baked. --- */
:root {
  --treatment-default: documentary-muted;
  --treatment-documentary-muted-filter: saturate(0.72) contrast(1.03);
  --treatment-documentary-muted-grain:  0.05;
  --treatment-navy-duotone-filter:      grayscale(1) contrast(1.05);
  --treatment-navy-duotone-shadow:      #131257;
  --treatment-navy-duotone-mid:         #3A5B9F;
  --treatment-navy-duotone-highlight:   #F5E2DA;
  --treatment-navy-duotone-strength:    0.42;
  --treatment-navy-duotone-grain:       0.05;
  --treatment-midnight-graded-filter:   saturate(0.5) contrast(1.05);
  --treatment-midnight-graded-shadow:   #020381;
  --treatment-midnight-graded-mid:      #2874fc;
  --treatment-midnight-graded-highlight:#DCE8FF;
  --treatment-midnight-graded-strength: 0.30;
  --treatment-midnight-graded-grain:    0.05;
  --treatment-blush-warm-filter:        saturate(0.6) contrast(1.02);
  --treatment-blush-warm-shadow:        #2A1512;
  --treatment-blush-warm-mid:           #8A6A5C;
  --treatment-blush-warm-highlight:     #FFF0EA;
  --treatment-blush-warm-strength:      0.26;
  --treatment-blush-warm-grain:         0.06;
}
